def _calculate_discount_percentage(role: UserRole) -> Decimal:
    """Retrieve the discount percentage for a given user role from the predefined map."""
    discount = DISCOUNT_MAP.get(role)
    if discount is None:
        raise ValidationError(f"No discount configuration found for role: {role}")
    return discount


def _calculate_cart_total(cart_items: list[CartItem]) -> Decimal:
    """Calculate the total price of all items in the cart."""
    total = Decimal("0")
    for item in cart_items:
        subtotal = item.subtotal
        total += subtotal
        if total > Decimal("9999999.99"):
            raise ValidationError("Cart total exceeds maximum allowed amount.")
    return total.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def _apply_discount(total: Decimal, discount_percentage: Decimal) -> tuple[Decimal, Decimal]:
    """Apply the discount to the total and return (discount_amount, final_amount)."""
    if discount_percentage < Decimal("0") or discount_percentage > Decimal("100"):
        raise ValidationError("Discount percentage must be between 0 and 100.")

    discount_amount = (total * discount_percentage / Decimal("100")).quantize(
        Decimal("0.01"), rounding=ROUND_HALF_UP
    )
    final_amount = (total - discount_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

    if final_amount < Decimal("0"):
        raise ValidationError("Final amount cannot be negative after discount.")

    return discount_amount, final_amount


