    """
    Main payment processing function.

    Validates the user's role, calculates the appropriate discount,
    applies it to the cart total, and processes the payment.

    Args:
        user: User object with role field.
        cart_items: List of CartItem objects.
        payment_details: PaymentDetails object with payment info.

    Returns:
        PaymentResult with transaction details.

    Raises:
        ValidationError: If input validation fails.
        InsufficientDataError: If required data is missing.
        PaymentProcessingError: If payment processing fails.
    """
    # Validate inputs
    if not isinstance(user, User):
        raise ValidationError("Invalid user object provided.")
    if not isinstance(payment_details, PaymentDetails):
        raise ValidationError("Invalid payment details provided.")
    if not isinstance(cart_items, list):
        raise ValidationError("Cart items must be a list.")
    if len(cart_items) == 0:
        raise InsufficientDataError("Cart is empty. Cannot process payment.")
    if len(cart_items) > 1000:
        raise ValidationError("Too many items in cart.")

    for idx, item in enumerate(cart_items):
        if not isinstance(item, CartItem):
            raise ValidationError(f"Invalid cart item at index {idx}.")

    # Calculate discount based on user role
    discount_percentage = _calculate_discount_percentage(user.role)
    logger.info(
        "User %s (role: %s) qualifies for %s%% discount.",
        user.user_id,
        user.role.value,
        discount_percentage,
    )

    # Calculate cart total
    cart_total = _calculate_cart_total(cart_items)
    logger.info("Cart total: %s", cart_total)

    # Apply discount
    discount_amount, final_amount = _apply_discount(cart_total, discount_percentage)
    logger.info(
        "Discount: %s (%s%%). Final amount: %s",
        discount_amount,
        discount_percentage,
        final_amount,
    )

    # Process payment
    if final_amount == Decimal("0"):
        logger.info("Final amount is zero after discount. No payment needed.")
        return PaymentResult(
            success=True,
            message="Order fully covered by discount. No payment charged.",
            cart_total=cart_total,
            discount_percentage=discount_percentage,
            discount_amount=discount_amount,
            final_amount=final_amount,
            user_id=user.user_id,
            payment_method=payment_details.method,
            items_count=len(cart_items),
        )

    payment_success = _process_payment_gateway(final_amount, payment_details, user)

    if not payment_success:
        raise PaymentProcessingError("Payment gateway rejected the transaction.")

    result = PaymentResult(
        success=True,
        message=f"Payment of {final_amount} processed successfully.",
        cart_total=cart_total,
        discount_percentage=discount_percentage,
        discount_amount=discount_amount,
        final_amount=final_amount,
        user_id=user.user_id,
        payment_method=payment_details.method,
        items_count=len(cart_items),
    )

    logger.info("Payment result: %s", result)
    return result


